diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 6737b50405ee..aac91eaa2215 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -2017,6 +2017,22 @@ Instruction *InstCombinerImpl::foldICmpAndConstant(ICmpInst &Cmp,
     }
   }

+  // (icmp eq (and (add X, -1), ~C), 0) -> (icmp ne (and X, C), 0)
+  // where C is a single bit. This is useful for range-restricted values.
+  // E.g., (x-1) & -3 == 0 -> x & 1 != 0  (when x is in [0, 4))
+  {
+    Value *X;
+    const APInt *Msk;
+    if (C.isZero() && Pred == CmpInst::ICMP_EQ &&
+        match(And, m_And(m_OneUse(m_Add(m_Value(X), m_AllOnes())),
+                         m_APInt(Msk))) &&
+        (*Msk + 1).isNegatedPowerOf2()) {
+      APInt BitVal = ~(*Msk + 1);  // C = -(mask+1) gives the single bit
+      Value *MaskX = Builder.CreateAnd(X, ConstantInt::get(X->getType(), BitVal));
+      return new ICmpInst(CmpInst::ICMP_NE, MaskX, Constant::getNullValue(X->getType()));
+    }
+  }
+
   return nullptr;
 }

